   116Ôćĺfunction generateMermaidDiagram(
   117Ôćĺ	tables: TableStructure[],
   118Ôćĺ	foreignKeys: ForeignKey[],
   119Ôćĺ): string {
   120Ôćĺ	const lines: string[] = ['erDiagram'];
   121Ôćĺ
   122Ôćĺ	for (const table of tables) {
   123Ôćĺ		const columnDefs: string[] = [];
   124Ôćĺ
   125Ôćĺ		for (const column of table.columns) {
   126Ôćĺ			const isPK = column.column_key === 'PRI';
   127Ôćĺ			const isFK = foreignKeys.some(
   128Ôćĺ				(fk) => fk.table_name === table.name && fk.column_name === column.column_name,
   129Ôćĺ			);
   130Ôćĺ			const isAuto = column.extra.includes('auto_increment');
   131Ôćĺ
   132Ôćĺ			let keyType = '';
   133Ôćĺ			if (isPK && isFK) {
   134Ôćĺ				keyType = ' PK,FK';
   135Ôćĺ			} else if (isPK) {
   136Ôćĺ				keyType = ' PK';
   137Ôćĺ			} else if (isFK) {
   138Ôćĺ				keyType = ' FK';
   139Ôćĺ			}
   140Ôćĺ
   141Ôćĺ			const attributes: string[] = [];
   142Ôćĺ			if (column.is_nullable === 'NO') {
   143Ôćĺ				attributes.push('NOT NULL');
   144Ôćĺ			}
   145Ôćĺ			if (isAuto) {
   146Ôćĺ				attributes.push('AUTO_INCREMENT');
   147Ôćĺ			}
   148Ôćĺ
   149Ôćĺ			const attributeStr = attributes.length > 0 ? ` "${attributes.join(', ')}"` : '';
   150Ôćĺ
   151Ôćĺ			columnDefs.push(
   152Ôćĺ				`        ${column.data_type} ${column.column_name}${keyType}${attributeStr}`,
   153Ôćĺ			);
   154Ôćĺ		}
   155Ôćĺ
   156Ôćĺ		lines.push(`    ${table.name} {`);
   157Ôćĺ		lines.push(...columnDefs);
   158Ôćĺ		lines.push('    }');
   159Ôćĺ	}
   160Ôćĺ
   161Ôćĺ	const processedRelations = new Set<string>();
   162Ôćĺ
   163Ôćĺ	for (const fk of foreignKeys) {
   164Ôćĺ		const relationKey = `${fk.table_name}-${fk.referenced_table_name}-${fk.column_name}`;
   165Ôćĺ		if (processedRelations.has(relationKey)) {
   166Ôćĺ			continue;
   167Ôćĺ		}
   168Ôćĺ		processedRelations.add(relationKey);
   169Ôćĺ
   170Ôćĺ		lines.push(
   171Ôćĺ			`    ${fk.referenced_table_name} ||--o{ ${fk.table_name} : "${fk.column_name}"`,
   172Ôćĺ		);
   173Ôćĺ	}
   174Ôćĺ
   175Ôćĺ	return lines.join('\n');
   176Ôćĺ}
