    83Ôćĺ
    84Ôćĺ	switch (pattern) {
    85Ôćĺ		case 'winter':
    86Ôćĺ			return month >= 11 || month <= 2 ? 1.8 : month >= 3 && month <= 5 ? 0.4 : 0.7;
    87Ôćĺ		case 'spring':
    88Ôćĺ			return month >= 3 && month <= 5 ? 1.6 : month >= 6 && month <= 8 ? 0.5 : 0.8;
    89Ôćĺ		case 'summer':
    90Ôćĺ			return month >= 6 && month <= 8 ? 1.7 : month >= 9 && month <= 11 ? 0.6 : 0.7;
    91Ôćĺ		case 'fall':
