   152Ôćĺfunction addTrend(date: Date, baseValue: number, startYear: number): number {
   153Ôćĺ	const daysSinceStart = Math.floor(
   154Ôćĺ		(date.getTime() - new Date(`${startYear}-01-01`).getTime()) / (1000 * 60 * 60 * 24),
   155Ôćĺ	);
   156Ôćĺ
   157Ôćĺ	// Add some long-term growth trend (2% per year)
   158Ôćĺ	const yearlyGrowth = 1 + (daysSinceStart / 365) * 0.02;
   159Ôćĺ
